<template>
  <tr>
    <td>
      <img
        alt="CSSLOP Logo"
        class="min-csslop-logo"
        src="data:image/png;base64,"
      >
    </td>
    <td>v{{ version }}</td>
    <td><pre><code v-text="output"></code></pre></td>
  </tr>
</template>

<script>
import { minifyCSS as minify } from '@thejaredwilcurt/csslop/index.js';

import { version } from '@thejaredwilcurt/csslop/package.json' with { type: 'json' };

export default {
  name: 'MinCsso',
  props: {
    input: {
      type: String,
      default: ''
    }
  },
  constants: {
    version
  },
  computed: {
    output: function () {
      return minify(this.input);
    }
  }
};
</script>

<style>
.min-csslop-logo {
  max-width: 50px;
}
</style>
